import React, { useEffect, useRef } from 'react';

interface InkCanvasProps {
  darkMode?: boolean;
}

const InkCanvas: React.FC<InkCanvasProps> = ({ darkMode = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const darkModeRef = useRef(darkMode);

  useEffect(() => {
    darkModeRef.current = darkMode;
  }, [darkMode]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    let time = 0;
    let animationFrameId: number;

    // --- Configuration ---
    const MOUNTAIN_LAYERS = 3;

    // --- Classes ---
    class Star {
        x: number;
        y: number;
        size: number;
        baseOpacity: number;
        speed: number;

        constructor() {
            this.x = Math.random() * width;
            this.y = Math.random() * height * 0.6;
            this.size = Math.random() * 1.5 + 0.5;
            this.baseOpacity = Math.random() * 0.8 + 0.2;
            this.speed = Math.random() * 0.02 + 0.005;
        }

        draw(ctx: CanvasRenderingContext2D, globalAlpha: number, time: number) {
            const twinkle = Math.sin(time * this.speed) * 0.3 + 0.7;
            ctx.fillStyle = `rgba(255, 255, 255, ${this.baseOpacity * twinkle * globalAlpha})`;
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
            ctx.fill();
        }
    }

    class MountainLayer {
      index: number;
      offset: number;
      speed: number;
      points: number[];

      constructor(index: number) {
        this.index = index;
        this.offset = Math.random() * 1000;
        this.speed = 0.05 * (3 - index); // Farther mountains move slower? Actually in parallax, closest moves fastest.
        this.points = [];
      }

      getY(x: number) {
        // Slow movement for serene effect
        const t = time * 0.005;
        // Parallax: higher index = closer = faster relative movement
        const moveSpeed = (this.index + 1) * 0.5; 
        const xOff = (x * 0.002) + this.offset + (t * moveSpeed);

        // Perlin-ish noise composition
        const noise = 
          Math.sin(xOff * 1.0) * 1.0 +
          Math.sin(xOff * 2.5) * 0.5 +
          Math.cos(xOff * 5.2) * 0.2;

        // Amplitude increases for closer mountains
        const amp = height * (0.15 + (this.index * 0.08));
        // Base height moves down for closer mountains
        const base = height * (0.6 + (this.index * 0.15)); 

        return base - (noise * amp);
      }

      draw(ctx: CanvasRenderingContext2D, darkness: number) {
        // Ink Wash Style:
        // Use gradients to simulate ink fading into mist at the bottom

        const gradient = ctx.createLinearGradient(0, height * 0.3, 0, height);

        // Color Palette Interpolation
        // Day: Mineral Blue/Grey
        // Night: Deep Charcoal/Black

        const r = 50 - (this.index * 10) - (darkness * 30);
        const g = 60 - (this.index * 5) - (darkness * 40);
        const b = 70 - (this.index * 2) - (darkness * 40);

        // Opacity is key for "Wash" effect (Watered down ink)
        // Far mountains are fainter (atmospheric perspective)
        const alphaTop = 0.1 + (this.index * 0.15) + (darkness * 0.3);
        const alphaBot = 0.0; // Fade to mist

        gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, 0)`); // Sky fade
        gradient.addColorStop(0.4, `rgba(${r}, ${g}, ${b}, ${alphaTop})`); // Peak solidity
        gradient.addColorStop(1, `rgba(${247, 244, 237, ${darkness > 0.5 ? 0 : 0.8}})`); // Fade into paper color (day) or transparency (night)

        ctx.fillStyle = gradient;

        ctx.beginPath();
        ctx.moveTo(0, height);

        // Draw the mountain ridge
        const step = 10;
        let firstY = this.getY(0);
        ctx.lineTo(0, firstY);

        for (let x = step; x <= width; x += step) {
             // Add some "ink bleed" roughness
             const rough = Math.random() * 2 * this.index; 
             ctx.lineTo(x, this.getY(x) + rough);
        }

        ctx.lineTo(width, height);
        ctx.closePath();
        ctx.fill();
      }
    }

    class InkBloom {
      x: number;
      y: number;
      radius: number;
      maxRadius: number;
      alpha: number;

      constructor() {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.radius = 0;
        this.maxRadius = Math.random() * 80 + 20;
        this.alpha = Math.random() * 0.05 + 0.02;
      }

      update() {
         if (this.radius < this.maxRadius) {
             this.radius += 0.5;
         } else {
             this.alpha -= 0.0005;
         }
      }

      draw(ctx: CanvasRenderingContext2D) {
         if (this.alpha <= 0) return;
         const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.radius);
         g.addColorStop(0, `rgba(40, 45, 50, ${this.alpha})`);
         g.addColorStop(1, `rgba(40, 45, 50, 0)`);
         ctx.fillStyle = g;
         ctx.beginPath();
         ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
         ctx.fill();
      }
    }

    // --- State ---
    const mountains: MountainLayer[] = [];
    const blooms: InkBloom[] = [];
    const stars: Star[] = [];

    const init = () => {
       mountains.length = 0;
       for(let i=0; i<MOUNTAIN_LAYERS; i++) {
         mountains.push(new MountainLayer(i));
       }
       stars.length = 0;
       for(let i=0; i<60; i++) {
         stars.push(new Star());
       }
    };

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      const dpr = window.devicePixelRatio || 1;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      ctx.scale(dpr, dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      init();
    };

    let currentDarkness = 0;

    const animate = () => {
      const targetDarkness = darkModeRef.current ? 1 : 0;
      currentDarkness += (targetDarkness - currentDarkness) * 0.03;

      ctx.clearRect(0, 0, width, height);
      time++;

      // Stars (Night only)
      if (currentDarkness > 0.01) {
          ctx.save();
          stars.forEach(s => s.draw(ctx, currentDarkness, time));
          ctx.restore();
      }

      // Random ink drops simulating clouds/mist
      if (Math.random() < 0.02) {
          blooms.push(new InkBloom());
      }
      for (let i = blooms.length - 1; i >= 0; i--) {
        blooms[i].update();
        blooms[i].draw(ctx);
        if (blooms[i].alpha <= 0) blooms.splice(i, 1);
      }

      // Mountains
      mountains.forEach(m => m.draw(ctx, currentDarkness));

      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className={`fixed inset-0 w-full h-full pointer-events-none z-0 transition-all duration-1000`}
    />
  );
};

export default InkCanvas;

